d3 = require("d3@7")
langs = transpose(lang_stats)
















// the language bubble pack from the original wordbank home page:
// one bubble per language, area ~ n_children^0.65, HCL rainbow by size rank
{
  const width = 450, height = 425;

  const root = d3.pack()
    .size([width, height])
    .padding(5)(
      d3.hierarchy({ children: langs })
        .sum((d) =&gt; Math.pow(d.count, 0.65))
        .sort((a, b) =&gt; b.value - a.value)
    );

  const color = new Map(langs.map((d, i) =&gt;
    [d.name, d3.hcl((i * 360 / langs.length) % 360, 60, 60).formatHex()]));

  const svg = d3.create("svg")
    .attr("viewBox", [0, 0, width, height])
    .attr("style", "max-width: 450px; width: 100%; height: auto; display: inline-block;");

  const node = svg.selectAll("g")
    .data(root.leaves())
    .join("g")
    .attr("transform", (d) =&gt; `translate(${d.x},${d.y})`);

  node.append("circle")
    .attr("r", (d) =&gt; d.r)
    .attr("fill", (d) =&gt; color.get(d.data.name));

  node.append("title")
    .text((d) =&gt; `${d.data.language}: ${d.data.count.toLocaleString()} children`);

  const ctx = document.createElement("canvas").getContext("2d");
  ctx.font = "12px sans-serif";
  const fontSize = (d) =&gt; {
    const w = ctx.measureText(d.data.name).width;
    return Math.max(0, Math.min(2 * d.r, (2 * d.r - 6) / w * 12));
  };

  node.append("text")
    .attr("dy", ".35em")
    .attr("text-anchor", "middle")
    .attr("fill", "white")
    .attr("style", "font-family: var(--sans-serif); pointer-events: none;")
    .style("font-size", (d) =&gt; fontSize(d) + "px")
    .text((d) =&gt; d.data.name);

  return svg.node();
}








Wordbank archives data from the MacArthur-Bates Communicative Development Inventories (CDIs), parent-report instruments that measure early language development. Data are contributed by researchers around the world and are freely available for browsing, visualization, and download. If you use Wordbank, please cite: Frank, M. C., Braginsky, M., Yurovsky, D., & Marchman, V. A. (2017). Wordbank: An open repository for developmental vocabulary data. Journal of Child Language, 44(3), 677–694. doi:10.1017/S0305000916000209

Compare the acquisition of word meanings across languages. Pick a “uni-lemma” (a cross-linguistic meaning, like dog) to see, for each language that has a mapped word, the proportion of children producing or understanding it at each age — optionally split by sex or consolidated onto a single plot.

san = (s) =&gt; s.toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "")

split_options = new Map([
  ["None", null],
  ["Sex", "sex"],
  ["Birth order", "birth_order"],
  ["Caregiver education", "caregiver_education"],
  ["Ethnicity", "ethnicity"]
])

level_orders = ({
  sex: ["Female", "Male", "Other"],
  birth_order: ["First", "Second", "Third", "Fourth", "Fifth", "Sixth",
                "Seventh", "Eighth"],
  caregiver_education: ["None", "Primary", "Some Secondary", "Secondary",
                        "Some College", "College", "Some Graduate", "Graduate"],
  ethnicity: ["Asian", "Black", "Hispanic", "White", "Other"]
})

level_sort = (split) =&gt; {
  const order = split ? (level_orders[split] ?? []) : [];
  return (a, b) =&gt; {
    const ia = order.indexOf(a), ib = order.indexOf(b);
    if (ia !== -1 || ib !== -1) return (ia === -1 ? 99 : ia) - (ib === -1 ? 99 : ib);
    return a &lt; b ? -1 : a &gt; b ? 1 : 0;
  };
}






























download_csv = (rows, filename) =&gt; {
  if (!rows || !rows.length) return html`&lt;span&gt;&lt;/span&gt;`;
  const cols = Object.keys(rows[0]);
  const esc = (v) =&gt; {
    const s = String(v ?? "");
    return /[",\n]/.test(s) ? '"' + s.replace(/"/g, '""') + '"' : s;
  };
  const csv = [cols.join(","), ...rows.map((r) =&gt; cols.map((c) =&gt; esc(r[c])).join(","))].join("\n");
  const url = URL.createObjectURL(new Blob([csv], { type: "text/csv" }));
  return html`&lt;a class="btn btn-sm btn-outline-primary" href=${url} download=${filename}&gt;Download CSV&lt;/a&gt;`;
}







loess_points = (data, { x = "age", y = "prop", w = null, span = 0.75, grid = 60 } = {}) =&gt; {
  const pts = data
    .map((d) =&gt; ({ x: +d[x], y: +d[y], w: w ? +d[w] : 1 }))
    .filter((d) =&gt; Number.isFinite(d.x) && Number.isFinite(d.y))
    .sort((a, b) =&gt; a.x - b.x);
  if (pts.length &lt; 3) return pts.map((d) =&gt; ({ [x]: d.x, [y]: d.y }));

  const k = Math.max(2, Math.ceil(span * pts.length));
  const x0 = pts[0].x, x1 = pts[pts.length - 1].x;
  const out = [];
  for (let i = 0; i &lt;= grid; i++) {
    const xt = x0 + (x1 - x0) * (i / grid);
    const dists = pts.map((p) =&gt; Math.abs(p.x - xt)).sort((a, b) =&gt; a - b);
    const dmax = dists[Math.min(k, dists.length) - 1] || 1e-9;
    let sw = 0, swx = 0, swy = 0, swxx = 0, swxy = 0;
    for (const p of pts) {
      const t = Math.abs(p.x - xt) / dmax;
      if (t &gt;= 1) continue;
      const wt = Math.pow(1 - t * t * t, 3) * p.w;
      sw += wt; swx += wt * p.x; swy += wt * p.y;
      swxx += wt * p.x * p.x; swxy += wt * p.x * p.y;
    }
    if (sw &lt;= 0) continue;
    const denom = sw * swxx - swx * swx;
    const yt = Math.abs(denom) &lt; 1e-12
      ? swy / sw
      : (swy * swxx - swx * swxy) / denom + ((sw * swxy - swx * swy) / denom) * xt;
    out.push({ [x]: xt, [y]: yt });
  }
  return out;
}

// smooth each series (grouped by `series`) and tag points with the group
loess_series = (data, series, opts = {}) =&gt; {
  const groups = new Map();
  for (const d of data) {
    const key = d[series];
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(d);
  }
  return [...groups.entries()].flatMap(([key, rows]) =&gt;
    loess_points(rows, opts).map((p) =&gt; ({ ...p, [series]: key })));
}
















